const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
};

const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
const PROCESSING_FEE = 5;

export const processScenario = (scenario: Scenario): ScenarioResult => {
  const items = scenario.steps[0].items;
  const basePremium = items.length === 0 ? 0 : BASE_PREMIUMS[items[0].type];
  const premium =
    basePremium + basePremium * FIRST_INSURANCE_SURCHARGE_RATE + PROCESSING_FEE;
  return { results: [{ premium }] };
};

